class Solution:
    def tribonacci(self, n: int) -> int:
        if n == 0:
            return 0
        elif n == 1 or n == 2:
            return 1
        else:
            a, b, c = 0, 1, 1
            for _ in range(2, n + 1):
                a, b, c = b, c, a + b + c
            return c
